import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.LBeL10WQ.js";const g=JSON.parse('{"title":"Contest","description":"","frontmatter":{"title":"Contest"},"headers":[],"relativePath":"en/advertisers/co-branded-contest/index.md","filePath":"en/advertisers/co-branded-contest/index.md"}'),s={name:"en/advertisers/co-branded-contest/index.md"};function r(n,e,d,l,c,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="contest" tabindex="-1">Contest <a class="header-anchor" href="#contest" aria-label="Permalink to &quot;Contest&quot;">​</a></h1><p>The mechanism that combines <strong>awareness</strong>, <strong>qualified lead acquisition</strong>, and <strong>immediate conversion</strong> — thanks to the endorsement of a partner e-retailer.</p><hr><h2 id="available-mechanics" tabindex="-1">Available Mechanics <a class="header-anchor" href="#available-mechanics" aria-label="Permalink to &quot;Available Mechanics&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎟️ Golden Ticket</strong><p>A winning ticket is inserted directly into the distributor&#39;s parcels. The surprise at the moment of unboxing maximizes the emotional impact.</p></div><div class="gi-value-card"><strong>🎡 Wheel of Fortune</strong><p>Fun mechanics activated via a QR code (<em>&quot;Scan to spin the wheel&quot;</em>). High participation rate and natural virality.</p></div><div class="gi-value-card"><strong>🧠 Quiz / Profile</strong><p>Interactive format (<em>&quot;What is your profile?&quot;</em>) that generates exceptional engagement and qualifies leads at the same time.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Field Example</p><p>AJY (wellness brand) achieved a <strong>21.6% scan rate</strong> with a <em>&quot;Discover your Dosha&quot;</em> quiz — one of the highest scores observed on the network.</p></div><hr><h2 id="why-launch-a-contest" tabindex="-1">Why launch a contest? <a class="header-anchor" href="#why-launch-a-contest" aria-label="Permalink to &quot;Why launch a contest?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>📊 Lead Acquisition (Opt-in)</strong><p>In exchange for their participation, players agree to receive your offers. You enrich your CRM with <strong>consenting and qualified</strong> contacts based on the distributor&#39;s purchasing behavior.</p></div><div class="gi-value-card"><strong>💰 Conversion: no losers</strong><p>Each participant receives a **consolation promo code** (e.g., THANKS15). This transforms a free mechanic into immediate sales — even for those who do not win the grand prize.</p></div><div class="gi-value-card"><strong>❤️ Strong Engagement</strong><p>Gamification creates a positive emotional bond between your brand and the distributor&#39;s audience. You benefit from their credibility with their community.</p></div></div><hr><h2 id="your-investment" tabindex="-1">Your Investment <a class="header-anchor" href="#your-investment" aria-label="Permalink to &quot;Your Investment&quot;">​</a></h2><p>Apart from the media budget, you provide two elements:</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🏆 The Prize (Grand prizes)</strong><p>The draw product that attracts players. Example: <em>&quot;Win a year of products&quot;</em> or <em>&quot;3 × 100€ in vouchers&quot;</em>. You manage the shipping to the winners after the draw.</p></div><div class="gi-value-card"><strong>🎟️ Conolation Reward</strong><p>A generic promo code (e.g., <code>THANKS15</code>) offered to <em>all</em> participants. Simple to prepare, high impact on conversion.</p></div></div><hr><h2 id="_5-step-workflow" tabindex="-1">5-Step Workflow <a class="header-anchor" href="#_5-step-workflow" aria-label="Permalink to &quot;5-Step Workflow&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Brief &amp; Offer Definition</h3><p>Via the platform, provide the prizes (grand prize + consolation promo code), the visuals (packshots, HD logo), and select the partner distributor.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Setup (Distributor)</h3><p>The distributor creates a co-branded landing page on their site and activates their traffic channels (newsletter, banners, web push) to direct their community to the game.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Opt-in Collection (GDPR)</h3><p>Upon registration, the participant actively checks a box:</p><blockquote><em>☑ I agree to receive commercial offers from the partner [Your Brand Name].</em></blockquote><p>Only participants who have checked this box are transmitted and billed to you.</p></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Data Transfer &amp; Activation</h3><p>At the end of the campaign, the distributor sends you the secure CSV file of opt-in leads via getinside. Integrate them into your CRM (Mailchimp, Klaviyo...) and <strong>immediately</strong> send the welcome email with the promised promo code — timing is key to maximize conversion.</p></div></div><div class="gi-step"><div class="gi-step-num done">5</div><div class="gi-step-body"><h3>Draw</h3><p>You draw the grand prize winners and manage the shipping of the rewards directly to them.</p></div></div><div class="warning custom-block"><p class="custom-block-title">GDPR — mandatory rules</p><ul><li>The opt-in box must <strong>never</strong> be pre-checked.</li><li>Only participants who have voluntarily checked it are transmitted to you.</li><li>getinside provides legal notice templates validated by lawyers.</li></ul></div><hr><h2 id="pricing" tabindex="-1">Pricing <a class="header-anchor" href="#pricing" aria-label="Permalink to &quot;Pricing&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Item</th><th style="text-align:left;">Cost</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Platform Fee</strong></td><td style="text-align:left;">12% of invested media budget</td></tr><tr><td style="text-align:left;"><strong>Creative Studio</strong> (optional)</td><td style="text-align:left;">Flat fee 550€ HT per campaign</td></tr><tr><td style="text-align:left;"><strong>Prize</strong></td><td style="text-align:left;">At your expense (prizes + shipping to winners)</td></tr></tbody></table><hr><h2 id="why-go-through-getinside" tabindex="-1">Why go through getinside? <a class="header-anchor" href="#why-go-through-getinside" aria-label="Permalink to &quot;Why go through getinside?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚡ Turnkey</strong><p>getinside coordinates the technical setup with the distributor (landing page, data flow). You provide the prizes and visuals — that&#39;s it.</p></div><div class="gi-value-card"><strong>⚖️ GDPR Compliance</strong><p>Shared data collection is a major legal issue. Our opt-in templates validated by lawyers protect you and guarantee the usability of the collected database.</p></div></div>',27)])])}const u=t(s,[["render",r]]);export{g as __pageData,u as default};
